const resp = $input.first().json;
let text = resp?.choices?.[0]?.message?.content || '';
text = text.replace(/```json/gi,'').replace(/```/g,'').trim();
let book;
try { book = JSON.parse(text); }
catch(e){ throw new Error('Model gecerli JSON vermedi: ' + text.slice(0,200)); }
if (Array.isArray(book)) book = book[0];
if (!book || typeof book !== 'object') throw new Error('Beklenen kitap objesi gelmedi');
book.overwrite = $node['Prompt Hazırla'].json.guncelle === true;
return [{ json: book }];
